159	/// Returns where the backend `.so` lives (or would live), with NO side
160	/// effects: never builds, never clones, never touches the network.
161	///
162	/// Mirrors the discovery order of [`find_or_build_backend`] minus its
163	/// build/clone steps:
164	///
165	/// 1. `CUDA_OXIDE_BACKEND` env var, returned even when the file is missing
166	///    so the caller can report the configured-but-absent path.
167	/// 2. Project config (`.cargo/cuda-oxide.toml`), returned even when missing
168	///    so the caller can report the configured-but-absent path.
169	/// 3. Local repo build path (`crates/rustc-codegen-cuda/target/debug/...`).
170	/// 4. Cache path at `~/.cargo/cuda-oxide/librustc_codegen_cuda.so`.
171	///
172	/// `cargo oxide doctor` uses this so that a diagnostic run never triggers a
173	/// multi-minute backend build or a git clone before it can print anything.
174	pub fn backend_so_candidate(workspace_root: &Path, configured_backend: Option<&Path>) -> PathBuf {
175	    if let Ok(path) = std::env::var("CUDA_OXIDE_BACKEND") {
176	        return PathBuf::from(path);
177	    }
178	
179	    if let Some(path) = configured_backend {
180	        return path.to_path_buf();
181	    }
182	
183	    let codegen_crate = workspace_root.join("crates/rustc-codegen-cuda");
184	    if codegen_crate.is_dir() {
185	        return codegen_crate.join("target/debug/librustc_codegen_cuda.so");
186	    }
187	
188	    cache_directory()
189	        .map(|dir| dir.join("librustc_codegen_cuda.so"))
190	        .unwrap_or_else(|| PathBuf::from("librustc_codegen_cuda.so"))
191	}
