193	/// Why the cached backend is out of date, or that it is current. The two
194	/// stale variants drive different recovery (re-clone vs. rebuild in place);
195	/// see the module-level comment.
196	#[derive(Debug, PartialEq, Eq)]
197	enum CacheStatus {
198	    /// Cache is up to date; reuse the cached `.so`.
199	    Fresh,
200	    /// The running `cargo-oxide` binary is newer than the cache: the user
201	    /// upgraded the binary, so the cached source may no longer match it.
202	    StaleVsBinary,
203	    /// The cached backend source is newer than the cached `.so`: the source
204	    /// was advanced in place and the `.so` should be rebuilt from it.
205	    StaleVsSource,
206	    /// The cached `.so` was built against a different Rust toolchain than the
207	    /// active one: it links a `librustc_driver` hash that no longer resolves,
208	    /// so it must be re-cloned and rebuilt. Highest precedence: an unloadable
209	    /// `.so` is stale regardless of mtimes.
210	    StaleVsToolchain,
211	}
212	
213	/// Classifies the cached backend `.so` against the running `cargo-oxide`
214	/// binary (the user upgraded the binary) and the newest backend source input
215	/// (the developer advanced the source). When `source_dir` is `None`, or no
216	/// source inputs can be found under it, only the binary check applies.
217	/// Binary staleness takes precedence when both fire, since a binary upgrade
218	/// wants a fresh clone (which also picks up the newest source).
219	///
220	/// Conservative on errors: if we can't stat the cached `.so`, we report
221	/// [`CacheStatus::Fresh`] so a working cache is never invalidated on a failed
222	/// metadata read.
223	fn cached_backend_status(cached_so: &Path, source_dir: Option<&Path>) -> CacheStatus {
224	    let Ok(so_meta) = std::fs::metadata(cached_so) else {
225	        return CacheStatus::Fresh;
226	    };
227	    let Ok(so_mtime) = so_meta.modified() else {
228	        return CacheStatus::Fresh;
229	    };
230	
231	    // Toolchain check (highest precedence): a toolchain swap makes the cached
232	    // `.so` unloadable no matter what the mtimes say, so it wins over the
233	    // binary/source mtime signals below.
234	    if let Some(cache_dir) = cached_so.parent()
235	        && toolchain_fingerprint_mismatch(cache_dir)
236	    {
237	        return CacheStatus::StaleVsToolchain;
238	    }
239	
240	    let self_mtime = std::env::current_exe()
241	        .ok()
242	        .and_then(|p| std::fs::metadata(p).ok())
243	        .and_then(|m| m.modified().ok());
244	
245	    // Binary check: if we can't stat our own executable, fall through to the
246	    // source check rather than declaring the cache fresh, so the source
247	    // signal is still honoured.
248	    if matches!(self_mtime, Some(self_mtime) if self_mtime > so_mtime) {
249	        return CacheStatus::StaleVsBinary;
250	    }
251	
252	    let stale_vs_source = source_dir
253	        .and_then(newest_backend_source_mtime)
254	        .map(|src_mtime| src_mtime > so_mtime)
255	        .unwrap_or(false);
256	    if stale_vs_source {
257	        return CacheStatus::StaleVsSource;
258	    }
259	
260	    CacheStatus::Fresh
261	}
262	
263	/// File next to the cached `.so` recording the toolchain it was built against.
264	const TOOLCHAIN_FINGERPRINT_FILE: &str = "toolchain-fingerprint.txt";
265	
266	/// A stable fingerprint of the active Rust toolchain: the full `rustc -vV`
267	/// output (release, commit-hash, host, LLVM version). The cached backend `.so`
268	/// links against this toolchain's `librustc_driver`, so any change here means
269	/// the cache can no longer be loaded.
270	fn current_toolchain_fingerprint() -> Option<String> {
271	    let output = Command::new("rustc").args(["-vV"]).output().ok()?;
272	    output
273	        .status
274	        .success()
275	        .then(|| String::from_utf8_lossy(&output.stdout).trim().to_string())
276	}
277	
278	/// True when the cached backend records a toolchain fingerprint that differs
279	/// from the active toolchain. Conservative: if the active fingerprint cannot be
280	/// read, or no fingerprint was recorded (a cache predating this check), returns
281	/// `false` and defers to the mtime checks rather than thrashing a working
282	/// cache. Pre-fingerprint caches are healed by the binary-mtime check on the
283	/// next `cargo-oxide` reinstall, or by `rm -rf ~/.cargo/cuda-oxide`.
284	fn toolchain_fingerprint_mismatch(cache_dir: &Path) -> bool {
285	    let Some(current) = current_toolchain_fingerprint() else {
286	        return false;
287	    };
288	    match std::fs::read_to_string(cache_dir.join(TOOLCHAIN_FINGERPRINT_FILE)) {
289	        Ok(stored) => stored.trim() != current,
290	        Err(_) => false,
291	    }
292	}
293	
294	/// Records the active toolchain fingerprint next to the cached `.so`. Best
295	/// effort: a write failure just means the next run re-detects a mismatch and
296	/// rebuilds again.
297	fn write_toolchain_fingerprint(cache_dir: &Path) {
298	    if let Some(fp) = current_toolchain_fingerprint() {
299	        let _ = std::fs::write(cache_dir.join(TOOLCHAIN_FINGERPRINT_FILE), fp);
300	    }
301	}
302	
303	/// Returns the newest mtime among the backend source inputs under
304	/// `source_dir`: every file in `src/**` plus the crate `Cargo.toml`.
305	///
306	/// Returns `None` when the directory cannot be located or yields no
307	/// readable inputs, which lets [`cached_backend_status`] degrade to the
308	/// binary-only check. The walk is best-effort: unreadable entries are
309	/// skipped rather than treated as failures.
310	fn newest_backend_source_mtime(source_dir: &Path) -> Option<SystemTime> {
311	    let mut newest: Option<SystemTime> = None;
312	
313	    let mut consider = |path: &Path| {
314	        if let Ok(mtime) = std::fs::metadata(path).and_then(|m| m.modified()) {
315	            newest = Some(match newest {
316	                Some(cur) if cur >= mtime => cur,
317	                _ => mtime,
318	            });
319	        }
320	    };
321	
322	    consider(&source_dir.join("Cargo.toml"));
323	    visit_files(&source_dir.join("src"), &mut consider);
324	
325	    newest
326	}
327	
328	/// Recursively visits every regular file under `dir`, calling `f` on each.
329	/// Best-effort: directories that cannot be read are skipped silently.
330	fn visit_files(dir: &Path, f: &mut dyn FnMut(&Path)) {
331	    let Ok(entries) = std::fs::read_dir(dir) else {
332	        return;
333	    };
334	    for entry in entries.flatten() {
335	        let path = entry.path();
336	        match entry.file_type() {
337	            Ok(ft) if ft.is_dir() => visit_files(&path, f),
338	            Ok(ft) if ft.is_file() => f(&path),
339	            _ => {}
340	        }
341	    }
342	}
343	
344	/// Drop both the cached `.so` and the cached source tree at `cache_dir`.
345	///
346	/// Removing `src/` is what forces the auto-fetch step to re-clone instead
347	/// of rebuilding from a checkout that was taken at first-install time.
348	/// Both removals are best-effort; if either fails (e.g. permissions), we
349	/// fall through to step 4, which will fail loudly with a clear error.
350	fn invalidate_cache(cache_dir: &Path) {
351	    eprintln!(
352	        "Detected upgraded cargo-oxide; refreshing cached backend at {} (issue #49).",
353	        cache_dir.display()
354	    );
355	    let _ = std::fs::remove_file(cache_dir.join("librustc_codegen_cuda.so"));
356	    let _ = std::fs::remove_dir_all(cache_dir.join("src"));
357	}
