359	/// Builds the backend from a local source tree.
360	pub fn build_backend_from_source(codegen_crate: &Path) {
361	    println!("Building rustc-codegen-cuda backend...");
362	
363	    let rustc_sysroot = get_rustc_sysroot();
364	    let lib_path = rustc_sysroot.as_ref().map(|s| format!("{}/lib", s));
365	
366	    let mut cmd = Command::new("cargo");
367	    cmd.args(["build"]).current_dir(codegen_crate);
368	
369	    if let Some(ref path) = lib_path {
370	        cmd.env("LIBRARY_PATH", build_library_path(path));
371	        cmd.env("LD_LIBRARY_PATH", build_ld_library_path(path));
372	    }
373	
374	    let status = cmd.status().expect("Failed to run cargo build");
375	
376	    if !status.success() {
377	        eprintln!("Failed to build rustc-codegen-cuda");
378	        std::process::exit(status.code().unwrap_or(1));
379	    }
380	
381	    let so_path = codegen_crate.join("target/debug/librustc_codegen_cuda.so");
382	    if so_path.exists() {
383	        println!("✓ Backend built: {}", so_path.display());
384	    } else {
385	        eprintln!("Warning: Expected .so not found at {}", so_path.display());
386	    }
387	}
