389	/// Returns the cache directory for cuda-oxide artifacts: `~/.cargo/cuda-oxide/`.
390	fn cache_directory() -> Option<PathBuf> {
391	    dirs_path().map(|d| d.join("cuda-oxide"))
392	}
393	
394	/// Resolves the Cargo home directory (`$CARGO_HOME` or `$HOME/.cargo`).
395	fn dirs_path() -> Option<PathBuf> {
396	    std::env::var("CARGO_HOME")
397	        .ok()
398	        .map(PathBuf::from)
399	        .or_else(|| {
400	            std::env::var("HOME")
401	                .ok()
402	                .map(|h| PathBuf::from(h).join(".cargo"))
403	        })
404	}
405	
406	/// Clones the cuda-oxide repo into the cache directory and builds the backend.
407	///
408	/// This is the last-resort discovery path for external users who don't have
409	/// the repo checked out locally. The clone is shallow (`--depth 1`) to keep
410	/// the download small.
411	fn auto_fetch_and_build() -> PathBuf {
412	    let cache_dir = cache_directory().unwrap_or_else(|| {
413	        eprintln!("Error: Cannot determine cache directory.");
414	        eprintln!("Set CARGO_HOME or HOME environment variable.");
415	        std::process::exit(1);
416	    });
417	
418	    let src_dir = cache_dir.join("src");
419	    let so_path = cache_dir.join("librustc_codegen_cuda.so");
420	
421	    std::fs::create_dir_all(&cache_dir).expect("Failed to create cache directory");
422	
423	    if !src_dir.join("Cargo.toml").exists() {
424	        eprintln!("Backend not found. Fetching cuda-oxide source (one-time setup)...");
425	        eprintln!();
426	        let status = Command::new("git")
427	            .args([
428	                "clone",
429	                "--depth",
430	                "1",
431	                "https://github.com/NVlabs/cuda-oxide.git",
432	                src_dir.to_str().unwrap(),
433	            ])
434	            .status()
435	            .expect("Failed to run git clone. Is git installed?");
436	
437	        if !status.success() {
438	            eprintln!("Failed to clone cuda-oxide repository.");
439	            eprintln!("You can manually set CUDA_OXIDE_BACKEND=/path/to/librustc_codegen_cuda.so");
440	            std::process::exit(1);
441	        }
442	    }
443	
444	    let codegen_crate = src_dir.join("crates/rustc-codegen-cuda");
445	    build_backend_from_source(&codegen_crate);
446	
447	    let built_so = codegen_crate.join("target/debug/librustc_codegen_cuda.so");
448	    if built_so.exists() {
449	        std::fs::copy(&built_so, &so_path).expect("Failed to copy backend to cache");
450	        write_toolchain_fingerprint(&cache_dir);
451	        eprintln!("✓ Backend cached at {}", so_path.display());
452	    }
453	
454	    so_path
455	}
