457	/// Returns the active rustc sysroot path (e.g., `~/.rustup/toolchains/nightly-...`).
458	///
459	/// Used to locate `libstd`, `librustc_driver`, and other compiler libraries that
460	/// must be on `LD_LIBRARY_PATH` when loading the codegen backend `.so`.
461	pub fn get_rustc_sysroot() -> Option<String> {
462	    let output = Command::new("rustc")
463	        .args(["--print", "sysroot"])
464	        .output()
465	        .ok()?;
466	
467	    if output.status.success() {
468	        Some(String::from_utf8_lossy(&output.stdout).trim().to_string())
469	    } else {
470	        None
471	    }
472	}
