474	/// Build LIBRARY_PATH preserving existing paths.
475	pub fn build_library_path(sysroot_lib: &str) -> String {
476	    if let Ok(existing) = std::env::var("LIBRARY_PATH") {
477	        format!("{}:{}", existing, sysroot_lib)
478	    } else {
479	        sysroot_lib.to_string()
480	    }
481	}
482	
483	/// Build LD_LIBRARY_PATH preserving existing paths (important for NixOS, etc.).
484	pub fn build_ld_library_path(sysroot_lib: &str) -> String {
485	    if let Ok(existing) = std::env::var("LD_LIBRARY_PATH") {
486	        format!("{}:{}", existing, sysroot_lib)
487	    } else {
488	        sysroot_lib.to_string()
489	    }
490	}
