687	    fn fresh_when_toolchain_fingerprint_matches() {
688	        let Some(fp) = current_toolchain_fingerprint() else {
689	            return; // no rustc here; nothing to assert
690	        };
691	        let year = Duration::from_secs(365 * 24 * 60 * 60);
692	        let dir = tempdir();
693	        let so = dir.join("librustc_codegen_cuda.so");
694	        write_with_mtime(&so, b"built", SystemTime::now() + year);
695	        std::fs::write(dir.join(TOOLCHAIN_FINGERPRINT_FILE), fp).unwrap();
696	
697	        assert_eq!(
698	            cached_backend_status(&so, None),
699	            CacheStatus::Fresh,
700	            "a matching fingerprint with fresh mtimes must be fresh"
701	        );
702	    }
703	
704	    /// A missing fingerprint file (a cache predating this check) must defer to
705	    /// the mtime checks rather than forcing a rebuild, so existing caches are
706	    /// not thrashed. Here the future-dated `.so` is therefore `Fresh`.
707	    #[test]
708	    fn missing_toolchain_fingerprint_defers_to_mtime() {
709	        let year = Duration::from_secs(365 * 24 * 60 * 60);
710	        let dir = tempdir();
711	        let so = dir.join("librustc_codegen_cuda.so");
712	        write_with_mtime(&so, b"built", SystemTime::now() + year);
713	        // No fingerprint file written.
714	        assert_eq!(
715	            cached_backend_status(&so, None),
716	            CacheStatus::Fresh,
717	            "absent fingerprint must defer to mtime checks (fresh here)"
718	        );
719	    }
720	
721	    /// The toolchain check has the highest precedence: a differing fingerprint
722	    /// wins even when the cache is also stale-vs-binary, because an unloadable
723	    /// `.so` must be re-cloned regardless of why else it is stale.
724	    #[test]
725	    fn toolchain_staleness_takes_precedence_over_binary() {
726	        let year = Duration::from_secs(365 * 24 * 60 * 60);
727	        let dir = tempdir();
728	        let so = dir.join("librustc_codegen_cuda.so");
729	        // Backdate the `.so` so binary-staleness would otherwise fire.
730	        write_with_mtime(&so, b"built", SystemTime::now() - year);
731	        std::fs::write(
732	            dir.join(TOOLCHAIN_FINGERPRINT_FILE),
733	            "rustc 0.0.0 (deadbeef 1970-01-01)",
734	        )
735	        .unwrap();
736	
737	        assert_eq!(
738	            cached_backend_status(&so, None),
739	            CacheStatus::StaleVsToolchain,
740	            "toolchain mismatch must win over binary staleness"
741	        );
742	    }
743	
744	    fn tempdir() -> PathBuf {
745	        let mut p = std::env::temp_dir();
746	        p.push(format!(
747	            "cargo-oxide-backend-test-{}-{}",
748	            std::process::id(),
749	            SystemTime::now()
750	                .duration_since(SystemTime::UNIX_EPOCH)
751	                .unwrap()
752	                .as_nanos()
753	        ));
754	        std::fs::create_dir_all(&p).unwrap();
755	        p
756	    }
757	
758	    fn write_with_mtime(path: &Path, contents: &[u8], mtime: SystemTime) {
759	        let mut f = OpenOptions::new()
760	            .create(true)
761	            .truncate(true)
762	            .write(true)
763	            .open(path)
764	            .unwrap();
765	        f.write_all(contents).unwrap();
