5	
6	//! Command implementations for cargo-oxide.
7	//!
8	//! These port the xtask commands with improvements:
9	//! - Backend path resolved via discovery chain instead of hardcoded relative path
10	//! - Workspace root resolved by walking up from CWD instead of assuming CWD
11	
12	use std::collections::BTreeMap;
13	use std::path::{Path, PathBuf};
14	use std::process::Command;
15	
16	use crate::backend;
17	
18	/// Project-local cuda-oxide defaults loaded from `.cargo/cuda-oxide.toml`.
19	#[derive(Debug, Clone, Default)]
20	pub struct OxideConfig {
21	    /// Explicit backend shared object path.
22	    pub backend: Option<PathBuf>,
23	    /// Default CUDA architecture for codegen commands.
24	    pub default_arch: Option<String>,
25	    /// Additional rustflags appended after cuda-oxide's required flags.
26	    pub extra_rustflags: Vec<String>,
27	    /// Environment variables applied to child Cargo invocations.
28	    pub env: Vec<(String, String)>,
29	}
30	
31	/// Pre-resolved context shared across all commands.
32	///
33	/// Built once at startup by [`resolve_context`] and passed by reference to
34	/// every command handler. Avoids repeated filesystem walks and backend builds.
35	pub struct Context {
36	    /// Absolute path to the workspace root (contains top-level `Cargo.toml`).
37	    pub workspace_root: PathBuf,
38	    /// Path to `crates/rustc-codegen-cuda` (backend source tree).
39	    pub codegen_crate: PathBuf,
